def is_right_triangle(p1, p2):
    if (p1[0] == 0 and p1[1] == 0) or (p2[0] == 0 and p2[1] == 0):
        return False
    if p1 == p2:
        return False
    if p1[0] * p2[1] == p1[1] * p2[0]:
        return False

    op2 = p1[0]**2 + p1[1]**2
    oq2 = p2[0]**2 + p2[1]**2
    pq2 = (p1[0]-p2[0])**2 + (p1[1]-p2[1])**2

    if op2 + oq2 == pq2 or op2 + pq2 == oq2 or oq2 + pq2 == op2:
        return True
    return False

def count_right_triangles(limit):
    count = 0
    points = []
    for x in range(limit + 1):
        for y in range(limit + 1):
            if x == 0 and y == 0:
                continue
            points.append((x, y))

    n = len(points)
    for i in range(n):
        for j in range(i + 1, n):
            if is_right_triangle(points[i], points[j]):
                count += 1
    return count

