        return None
    def eval4(a, b, c, d, op1, op2, op3):
        try:
            A, B, C, D = map(Fraction, [a, b, c, d])
            temp1 = operate(C, op3, D)
            temp2 = operate(B, op2, temp1)
            result = operate(A, op1, temp2)
            if result > 0 and result.denominator == 1:
                return int(result.numerator)
        except:
            pass
        return None
    def eval5(a, b, c, d, op1, op2, op3):
        try:
            A, B, C, D = map(Fraction, [a, b, c, d])
            temp1 = operate(A, op1, B)
            temp2 = operate(C, op3, D)
            result = operate(temp1, op2, temp2)
            if result > 0 and result.denominator == 1:
                return int(result.numerator)
        except:
            pass
        return None
    evaluators = [eval1, eval2, eval3, eval4, eval5]
    for perm in perms:
