        nonlocal best_set, min_sum

        if len(current_set) == n:
            s = sum(current_set)
            if s < min_sum:
                min_sum = s
                best_set = list(current_set)
            return

        # Pruning
        if sum(current_set) + (n - len(current_set)) * start_val >= min_sum:
            return

        # The range of elements can be estimated.
        # For n=6, the max element is 25.
        # For n=7, the max element might be around 30-40.
        for val in range(start_val, 45):
