                if (maskB & maskC) == 0:
                    if sB == sC:
                        return False

        for k in range(2, n + 1):
            # Only check if we have enough subsets of size k and k-1
            sums_k = [s for mask, s, count in subset_sums if count == k]
            sums_k_minus_1 = [s for mask, s, count in subset_sums if count == k - 1]
            if sums_k and sums_k_minus_1:
