        phi = m
        temp_m = m
        d = 2
        while d * d <= temp_m:
            if temp_m % d == 0:
                phi = phi // d * (d - 1)
                while temp_m % d == 0:
                    temp_m //= d
            d += 1
        if temp_m > 1:
            phi = phi // temp_m * (temp_m - 1)

        # The order must divide phi.
        # Find all divisors of phi.
        divs = []
        for i in range(1, int(phi**0.5) + 1):
            if phi % i == 0:
                divs.append(i)
                if i*i != phi:
                    divs.append(phi // i)
