import math

MOD = 1000000007

def W_rem(L, R):
    if R < 0:
        return 0
    if L < 0:
        return 1 if R == 0 else 0
    if R == 0:
        return 1
    ans = math.comb(L + R - 1, R)
    if R >= 10:
        ans -= L * math.comb(L + R - 11, R - 10)
    return ans

def W_orig(d, n):
    if n < 0 or n > 9 * d:
        return 0
    return W_rem(d, 9 * d - n)

def solve_k(k):
    n = k**3
    m = k**4

    d = (n + 8) // 9
    while True:
        if W_orig(d, n) >= m:
            break
        d += 1

    if d > 1:
        m -= W_orig(d - 1, n)

    r = 9 * d - n

    c1 = -1
    for v in range(min(r, 8), -1, -1):
        ways = W_rem(d - 1, r - v)
        if m <= ways:
            c1 = v
            break
        m -= ways

    R = r - c1
    i = 2

    non_zeros = [(1, c1)] if c1 > 0 else []

    while R > 0 and i <= d:
        low = 0
        high = d - i + 1
        best_k = 0
        while low <= high:
            mid = (low + high) // 2
            fk = W_rem(d - i + 1, R) - W_rem(d - i + 1 - mid, R)
            if fk < m:
                best_k = mid
                low = mid + 1
            else:
                high = mid - 1

        k = best_k
        fk = W_rem(d - i + 1, R) - W_rem(d - i + 1 - k, R)
        m -= fk

        j = i + k
        if j > d:
            break

        cj = -1
        for v in range(min(R, 9), 0, -1):
            ways = W_rem(d - j, R - v)
            if m <= ways:
                cj = v
                break
            m -= ways

        non_zeros.append((j, cj))
        R -= cj
        i = j + 1

    val = (pow(10, d, MOD) - 1) % MOD
    for pos, c in non_zeros:
        val = (val - c * pow(10, d - pos, MOD)) % MOD
    return val % MOD

